// src/UploadBills.jsx
import React, { useState } from "react";
import axios from "axios";
import { useNavigate } from "react-router-dom";

const API_BASE = "https://prasa-app-yde3.onrender.com/api/app";

export default function UploadBills({ employee }) {
  const navigate = useNavigate();
  const [files, setFiles] = useState(null);

  const handleUpload = async () => {
    if (!files || files.length === 0) {
      alert("Please select at least one file");
      return;
    }

    const formData = new FormData();
    for (let f of files) {
      formData.append("file", f); // multer.single("file")
    }
    formData.append("empId", employee.empld);

    try {
      const res = await axios.post(`${API_BASE}/upload-bill`, formData, {
        headers: { "Content-Type": "multipart/form-data" },
      });

      if (res.data.success) {
        alert("Bills uploaded successfully!");
        setFiles(null);
      } else {
        alert("Upload failed");
      }
    } catch (err) {
      console.error("UploadBills error:", err);
      alert("Server error while uploading bills");
    }
  };

  const green = "#0f9d58";
  const light = "#eaf8f0";

  return (
    <div
      style={{
        background: light,
        minHeight: "100vh",
        padding: 25,
        display: "flex",
        justifyContent: "center",
      }}
    >
      <div
        style={{
          width: "90%",
          maxWidth: 750,
          background: "#fff",
          padding: 22,
          borderRadius: 18,
          boxShadow: "0 4px 12px rgba(0,0,0,0.1)",
        }}
      >
        {/* Header */}
        <div style={{ display: "flex", alignItems: "center", gap: 12 }}>
          <button
            onClick={() => navigate("/addnew")}
            style={{
              background: light,
              border: "none",
              padding: "10px 14px",
              borderRadius: 12,
              fontSize: 18,
              cursor: "pointer",
            }}
          >
            ←
          </button>

        <h2 style={{ color: green, margin: 0 }}>Upload Bills</h2>
        </div>

        <p style={{ marginTop: 10, color: "#555" }}>
          Employee: {employee.name} • {employee.empld}
        </p>

        {/* Upload section */}
        <div
          style={{
            background: light,
            padding: 18,
            borderRadius: 14,
            marginTop: 18,
          }}
        >
          <label style={{ fontWeight: 600, fontSize: 15 }}>Choose Bills</label>

          <input
            type="file"
            multiple
            onChange={(e) => setFiles(e.target.files)}
            style={{
              width: "100%",
              padding: 10,
              marginTop: 10,
              borderRadius: 10,
            }}
          />

          <button
            onClick={handleUpload}
            style={{
              marginTop: 15,
              width: "100%",
              background: green,
              color: "white",
              border: "none",
              padding: "12px 0",
              borderRadius: 10,
              cursor: "pointer",
              fontSize: 16,
            }}
          >
            Upload
          </button>
        </div>
      </div>
    </div>
  );
}
